import { Anchor } from '@codecademy/gamut';
import { Meta } from '@storybook/addon-docs/blocks';

import { AboutHeader, Callout, LinkTo } from '~styleguide/blocks';

export const parameters = {
  id: 'Contributing',
  title: 'Contributing',
  subtitle: `Thanks so much for being interested in contributing to Gamut!
We love working with Codecademy employees across all our teams.`,
  status: 'static',
};

<Meta title="Meta/Contributing" />

<AboutHeader {...parameters} />

## Prework

We track planned work for Gamut components in the [Gamut Board](https://skillsoftdev.atlassian.net/jira/software/projects/GM/boards/784) on JIRA.

- If there's a ticket there you want to take on, send a Slack to #gamut-team or come to Gamut Office hours and lets talk about it!
- If the work you'd like to do isn't captured in a JIRA ticket, talk to us and we can work with you to create that ticket.
- If you would like to make a request for work to be done, please discuss with us on Slack or during Gamut Office Hours.
- If you'd like to pitch a change to the design system, please attend Gamut Crit, come to Gamut Office Hours, or send a Slack message to #gamut-team.

## Writing components

### Component structure

Create your component as an `index.tsx` file in a PascalCase-named folder within its package directory, such as `packages/gamut/src/ProgressBar/index.tsx`.
Consider saving this recommended format as an editor snippet:

```tsx
import React from 'react';

export type MyComponentProps = {
  /* ... */
};

export const MyComponent: React.FC<MyComponentProps> = (
  {
    /* ... */
  }
) => {
  // ...
};
```

#### Props documentation

With the exception of widespread, self-documenting props such as `onClick`, please include a sentence cased description of the prop's intent.
React props on the component will be picked up by Storybook and added to the component's documentation story.
We prefer these be full sentences.

```ts
/**
 * Number of lines to limit the message to.
 */
limit: number;
```

- If your comment purely restartes the name and type of variable, please either elaborate on it or remove the comment altogether.
- Consider starting comments for booleans with _"Whether "_.

### Unit tests

Your component should have unit tests in a `__tests__/MyComponent-test.tsx` file within its directory.
Use `setupRtl` from `gamut-tests` to test it.

We generally try to unit test all component logic, with the exception of class names in components that contain other logic.

### Stories

All components must have Storybook stories showing their use. See <LinkTo id='Meta/Stories'>Stories</LinkTo> for documentation.

## Pull requests

Please fill out the pull request template, including links to the corresponding Abstract design and JIRA ticket.

<Callout
  text={
    <>
      You can use a{' '}
      <Anchor
        target="_"
        href="https://help.github.com/en/github/collaborating-with-issues-and-pull-requests/about-pull-requests#draft-pull-requests"
      >
        Draft PR
      </Anchor>{' '}
      to just run CI jobs. That includes deploying a Netlify preview and
      publishing alpha package versions to npm. 😉
    </>
  }
/>

### Publishing updates

If you know your PR has breaking changes in at least one downstream repository, such as the [codecademy-engineering/mono](https://github.com/codecademy-engineering/mono):

1. Before merging it, create PRs in those downstream repositories using your PR's published alpha package versions
2. Verify those PRs work as expected and get them signed off normally
3. Merge your Gamut PR
4. Wait until the new Gamut package is published, then update the downstream repository PRs to use it
5. Merge and deploy those PRs as soon as possible

If your PR contains breaking changes that might affect other users, please mention them in the `#frontend` Slack channel.

meta-deep-controls-add-on--docs.content:
import { Meta } from '@storybook/addon-docs/blocks';

import { Callout, ImageWrapper, LinkTo } from '~styleguide/blocks';

export const parameters = {
  id: 'Deep Controls Add-On',
  title: 'Deep Controls Add-On',
  subtitle: `Enables Storybook controls for nested component properties, allowing you to interactively modify deeply nested props directly from the Controls panel without having to manually edit complex object structures.`,
  status: 'static',
};

<Meta title="Meta/Deep Controls add-on" />

# Deep Controls add-on

The Deep Controls add-on enables Storybook controls for nested component properties, allowing you to interactively modify deeply nested props directly from the Controls panel without having to manually edit complex object structures.

## Overview

By default, Storybook's Controls panel displays object-type props as a single collapsible JSON editor. The Deep Controls add-on extends this functionality by exposing individual nested properties as separate, dedicated controls with their own type-specific inputs (radio buttons, checkboxes, text fields, etc.).

<Callout text="Simply adding nested args to your stories will automatically create controls for them. You only need to define `argTypes` when you want to customize the controls, add descriptions, or restrict options." />

## Basic usage

### Minimal setup

The simplest way to use deep controls is to just provide nested args. The add-on will automatically create controls for them:

```typescript
import type { Meta, StoryObj } from '@storybook/react';
import type { TypeWithDeepControls } from 'storybook-addon-deep-controls';
import { MyComponent } from './MyComponent';

const meta: TypeWithDeepControls<Meta<typeof MyComponent>> = {
  component: MyComponent,
  args: {
    popoverProps: {
      beak: 'center',
      outline: false,
      position: 'below',
    },
  },
};

export default meta;
type Story = StoryObj<typeof MyComponent>;
```

That's it! The add-on will automatically generate controls for `popoverProps.beak`, `popoverProps.outline`, and `popoverProps.position` based on their inferred types:

<ImageWrapper
  src="./meta/deep_controls_default.png"
  alt="The Deep Controls add-on in action, with default args for popoverProps."
  height="auto"
/>

### Customizing controls

You only need to define `argTypes` if you want to customize the controls, types, or add descriptions. Otherwise, the default behavior works automatically.

To customize controls, use dot notation in `argTypes`:

```typescript
const meta: TypeWithDeepControls<Meta<typeof MyComponent>> = {
  component: MyComponent,
  args: {
    popoverProps: {
      beak: 'center',
      outline: false,
    },
  },
  argTypes: {
    'popoverProps.beak': {
      control: 'radio',
      options: ['left', 'right', 'center'],
      table: {
        type: { summary: 'left | right | center' },
      },
      description: 'Which side to position the beak.',
    },
    'popoverProps.outline': {
      control: 'boolean',
      table: {
        type: { summary: 'boolean' },
      },
      description: 'Whether to add outline style.',
    },
  },
};

export default meta;
type Story = StoryObj<typeof MyComponent>;
```

The controls panel will now show the following:

<ImageWrapper
  src="./meta/deep_controls_argTypes.png"
  alt="The Deep Controls add-on in action, with nested properties exposed as separate controls."
  height="auto"
/>

### Typescript errors

If you see TypeScript errors when using dot notation in `argTypes`, you may need to add the `TypeWithDeepControls` type to your story and wrap your `Meta` type in it (or `Story` type if you're using a story-level `argTypes`).

```typescript
import type { TypeWithDeepControls } from 'storybook-addon-deep-controls';
import type { Meta, StoryObj } from '@storybook/react';

const meta: TypeWithDeepControls<Meta<typeof MyComponent>> = {
  component: MyComponent,
  args: {
    ...
  },
  argTypes: {
    ...
  },
};
```

### When to use `argTypes`

Define `argTypes` for nested properties when you want to:

- **Restrict options**: Use `radio` or `select` controls with specific options instead of free-form text
- **Add descriptions**: Provide helpful documentation for each property
- **Customize controls**: Override the auto-detected control type (e.g., use a range slider for numbers)
- **Specify type summaries**: Add type information to the documentation table
- **Set default values**: Show default values in the documentation
- **Disable the parent object**: Hide the parent object from the controls table to reduce clutter (only useful when you're providing default args; see below)

### Hiding the parent object

<Callout text="If you're NOT providing default args for the nested object, there's no need to disable the parent. The deep controls will only show the nested properties you're actively using." />

When you DO NOT provide default args for a nested object but are setting the `argTypes` for the nested properties, the controls panel will show both the parent object AND the individual nested properties. For example:

```typescript
args: {},
argTypes: {
  'infotip.info': {
    control: 'text',
    table: {
      type: { summary: 'string' },
    },
    description: 'The text for the infotip.',
  },
  'infotip.emphasis': {
    control: 'radio',
    options: ['high', 'low'],
    table: {
      type: { summary: 'high | low' },
    },
  },
}
```

This will display:

- `infotip` (the entire object)
- `infotip.info` (individual property)
- `infotip.emphasis` (individual property)

To avoid this redundancy and keep your controls panel clean, disable the parent object in `argTypes`:

```typescript
argTypes: {
  infotip: {
    table: {
      disable: true, // Hides the parent object
    },
  },
}
```

## Advanced usage

### Reusable `argTypes`

For props that are reused across multiple components (like `infotip`), extract the `argTypes` to a shared module:

```typescript
// .storybook/argTypes/infotip.tsx
export const infotipNestedArgTypes = {
  infotip: {
    table: {
      disable: true, // Hide parent to avoid redundancy when default args are provided
    },
  },
  'infotip.emphasis': {
    control: 'radio',
    options: ['high', 'low'],
    table: {
      defaultValue: { summary: 'low' },
      type: { summary: 'high | low' },
    },
  },
  'infotip.alignment': {
    control: 'radio',
    options: ['bottom-left', 'bottom-right', 'top-left', 'top-right'],
    table: {
      defaultValue: { summary: 'top-right' },
      type: { summary: 'bottom-left | bottom-right | top-left | top-right' },
    },
  },
  'infotip.narrow': {
    control: 'boolean',
    table: {
      type: { summary: 'boolean' },
    },
    description:
      'Forces the tooltip to be its narrowest width. For use along the edges of the page or other tight spaces.',
  },
  'infotip.info': {
    control: 'text',
    table: {
      type: { summary: 'string' },
    },
    description: 'The text for the infotip.',
  },
} as const;
```

**Using in a story:**

```typescript
import type { Meta, StoryObj } from '@storybook/react';
import type { TypeWithDeepControls } from 'storybook-addon-deep-controls';
import { infotipNestedArgTypes } from '~styleguide/argTypes';

const meta: TypeWithDeepControls<Meta<typeof FormGroup>> = {
  component: FormGroup,
  argTypes: {
    ...infotipNestedArgTypes,
    // Add other component-specific argTypes here
  },
};

export default meta;
```

## Examples in the codebase

- <LinkTo id="Molecules/Alert">**Alert**</LinkTo> Demonstrates deep controls with
  default args for `cta`.

- <LinkTo id="Molecules/Coachmark">**Coachmark**</LinkTo> Demonstrates deep controls
  with custom `argTypes` for `popoverProps` with multiple nested properties like
  `beak`, `position`, `align`, and offsets.

- <LinkTo id="Atoms/FormElements/FormGroup">**FormGroup**</LinkTo> Uses the reusable
  `infotipNestedArgTypes` to expose infotip configuration.

meta-eslint-rules--docs.content:
import { Meta } from '@storybook/addon-docs/blocks';

import { AboutHeader, Callout, LinkTo } from '~styleguide/blocks';

export const parameters = {
  id: 'ESLint rules',
  title: 'ESLint rules',
  subtitle: 'Custom ESLint rules for Gamut projects',
  status: 'current',
};

<Meta title="Meta/ESLint rules" />

<AboutHeader {...parameters} />

The `eslint-plugin-gamut` package provides custom ESLint rules to enforce best practices and maintain code quality across Gamut projects. These rules help ensure consistent styling patterns and proper usage of Gamut components.

## Available rules

### `gamut/no-inline-style`

**Level:** `error`

Disallows the use of inline `style` props on JSX elements. This rule encourages the use of styled components, CSS classes, or design system utilities instead of inline styles.

**Why?** Inline styles make it harder to maintain consistent styling, can't be optimized by build tools, and don't benefit from our design token system.

#### ❌ Incorrect

```tsx
// Don't use inline style objects
<div style={{ padding: 0, margin: 10 }} />

// Even with variables
<Component style={customStyles} />

// Or with dynamic values
<Alert style={{ width: isOpen ? '100%' : '50%' }} />
```

#### ✅ Correct

```tsx
// Use styled components
import styled from '@emotion/styled';
import { css } from '@codecademy/gamut-styles';
import { Box } from '@codecademy/gamut';

const Container = styled(Box)(
  css({
    p: 0,
    m: 10,
  })
)

// Use system props from Box components
import { Box } from '@codecademy/gamut';

<Box p={0} m={10} />

// Use states utility for conditional styling
import { states } from '@codecademy/gamut-styles';
import styled from '@emotion/styled';

const ExpandableContainer = styled.Box(
  css({
    width: '50%',
  }),
  states({
    isExpanded: { width: '100%' },
  })
);

<ExpandableContainer isExpanded={isExpanded} />

// If need be, use className with CSS modules or global styles
<div className="my-component" />
```

#### Disabling the rule

For third-party components or edge cases where inline styles are necessary (e.g., framer-motion animations), you can disable the rule:

```tsx
// eslint-disable-next-line gamut/no-inline-style
<motion.div style={{ transformOrigin: 'center' }} />
```

---

### `gamut/no-css-standalone`

**Level:** `error`

Prevents importing standalone `.css` or `.scss` files. This rule enforces the use of CSS-in-JS solutions that integrate with our design system.

**Why?** Standalone stylesheets bypass our theming system, can cause specificity conflicts, and don't benefit from component-scoped styling.

#### ❌ Incorrect

```tsx
// Don't import CSS/SCSS files
import './styles.css';
import '../components/Button.scss';
```

#### ✅ Correct

```tsx
// Use styled components
import styled from '@emotion/styled';
import { StrokeButton } from '@codecademy/gamut';
import { css } from '@codecademy/gamut-styles';

const StyledStrokeButton = styled(StrokeButton)(
  css({
    p: 32,
    bg: 'primary',
  })
);

// Use utility functions from gamut-styles
import { variant } from '@codecademy/gamut-styles';

const buttonStyles = variant({
  variants: {
    primary: {
      p: 16,
      bg: 'primary',
    },
  },
});
```

---

### `gamut/import-paths`

**Level:** `error`
**Fixable:** Yes (auto-fixable using `--fix`)

Ensures Gamut import statements use proper module paths. This rule enforces three requirements:

1. Use relative imports when importing from the same package
2. Don't append `/src` to import paths
3. Don't append `/dist` to import paths

**Why?** Proper import paths ensure compatibility across different environments and make refactoring easier.

#### ❌ Incorrect

```tsx
// Don't use package imports within the same package
// (when in @codecademy/gamut package)
import { FillButton } from '@codecademy/gamut';

// Don't append /src
import { FillButton } from '@codecademy/gamut/src';

// Don't append /dist
import { theme } from '@codecademy/gamut-styles/dist';
```

#### ✅ Correct

```tsx
// Use relative imports within the same package
import { Box } from '../Box';

// Use clean package imports from other packages
import { FillButton } from '@codecademy/gamut';
import { theme } from '@codecademy/gamut-styles';
```

<Callout text="This rule includes auto-fix capabilities for /src and /dist violations!" />

---

### `gamut/prefer-themed`

**Level:** `off` (by default)
**Fixable:** Yes (auto-fixable using `--fix`)

Suggests using the `themed()` utility from `gamut-styles` instead of directly accessing theme values in styled components. When enabled, this rule helps maintain consistent theme access patterns.

**Why?** The `themed()` utility provides better type safety and ensures proper theme value resolution.

#### ❌ Flagged (when enabled)

```tsx
const StyledDiv = styled.div`
  color: ${({ theme }) => theme.colors.primary};
`;
```

#### ✅ Preferred

```tsx
import { css, themed } from '@codecademy/gamut-styles';
import { Box } from '@codecademy/gamut';

const StyledBox = styled(Box)(
  css({
    color: themed('colors.primary'),
  })
);
```

<Callout text="This rule is disabled by default but can be enabled in your project's ESLint config." />

---

## Configuration

These rules are automatically included when you extend the recommended configuration:

```js
// .eslintrc.js
module.exports = {
  plugins: ['eslint-plugin-gamut'],
  rules: {
    'gamut/no-inline-style': 'error',
    'gamut/no-css-standalone': 'error',
    'gamut/import-paths': 'error',
    'gamut/prefer-themed': 'off',
  },
};
```

## Overriding rules

You can override rules for specific files or directories:

```js
// .eslintrc.js
module.exports = {
  overrides: [
    {
      files: ['packages/gamut-illustrations/**'],
      rules: {
        'gamut/no-inline-style': 'off',
      },
    },
  ],
};
```

## Related documentation

- <LinkTo id="Meta/Best Practices">Best Practices</LinkTo> - Learn about Gamut styling
  best practices
- <LinkTo id="Foundations/System/Props">System Props</LinkTo> - Using system props
  as an alternative to inline styles
- <LinkTo id="Foundations/System/Variants">Variants</LinkTo> - Creating styled variants
  with gamut-styles

