    100: '#ECEEED',
    200: '#D9DCDB',
    300: '#C6CAC9',
    400: '#B3B8B7',
    500: '#A5ACAF',
    600: '#8A9093',
    700: '#6F7477',
    800: '#565A5C',
    900: '#3D4041',
  },
  accent: {
    kelly: '#00B388',
    midnight: '#004C54',
    silver: '#A5ACAF',
    gold: '#C5B358',
  },

  success: '#10B981',
  warning: '#F59E0B',
