        hover: 'kelly-700',
      },
      border: {
        primary: 'kelly-500',
        secondary: 'kelly-200',
        tertiary: 'kelly-100',
        disabled: 'silver-400',
      },
    },
    dark: {
      text: {
        _: 'brand-white',
        accent: 'brand-accent',
        disabled: 'silver-500',
        secondary: 'silver-400',
      },
      feedback: {
        error: 'error',
        success: 'success',
        warning: 'warning',
      },
      background: {
        _: 'brand-black',
        contrast: 'brand-black',
        current: 'brand-black',
        primary: 'midnight-800',
        selected: 'midnight-700',
        disabled: 'midnight-700',
        hover: 'midnight-700',
        success: 'success',
        warning: 'warning',
        error: 'error',
      },
      shadow: {
        primary: 'brand-black',
        secondary: 'midnight-900',
      },
      primary: {
        _: 'brand-accent',
        hover: 'silver-400',
        inverse: 'brand-black',
      },
      secondary: {
        _: 'midnight-500',
